import { Component } from '@angular/core';
import { FormBuilder, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { finalize } from 'rxjs';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html'
})
export class LoginComponent {
  loading = false;
  error = '';

  readonly form = this.formBuilder.group({
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required]]
  });

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly authService: AuthService,
    private readonly router: Router
  ) {
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    this.loading = true;
    this.error = '';

    this.authService.login(this.form.getRawValue() as { email: string; password: string; })
      .pipe(finalize(() => (this.loading = false)))
      .subscribe({
        next: () => this.router.navigate(['/dashboard']),
        error: (error: { error?: { message?: string } }) => {
          this.error = error.error?.message ?? 'Login failed. Check your credentials.';
        }
      });
  }
}
<div class="glass-panel mx-auto max-w-xl p-8">
  <p class="text-sm font-semibold uppercase tracking-[0.32em] text-ink/45">Welcome back</p>
  <h2 class="section-title mt-3 text-4xl">Login</h2>
  <p class="mt-3 text-sm leading-6 text-ink/65">Continue to your dashboard and resume analysis workspace.</p>

  <form class="mt-8 space-y-4" [formGroup]="form" (ngSubmit)="submit()">
    <div>
      <label class="mb-2 block text-sm font-semibold text-ink/70">Email</label>
      <input class="field" type="email" formControlName="email" placeholder="you@example.com">
    </div>

    <div>
      <label class="mb-2 block text-sm font-semibold text-ink/70">Password</label>
      <input class="field" type="password" formControlName="password" placeholder="Enter your password">
    </div>

    <p *ngIf="error" class="rounded-2xl bg-poppy/10 px-4 py-3 text-sm font-medium text-poppy">{{ error }}</p>

    <button class="btn-primary w-full" type="submit" [disabled]="loading">
      {{ loading ? 'Signing in...' : 'Login' }}
    </button>
  </form>

  <p class="mt-6 text-sm text-ink/65">
    New here?
    <a class="font-bold text-pine" routerLink="/auth/register">Create an account</a>
  </p>
</div>
